mapper.insert:
INSERT INTO ATTENDANCE_REQUESTS (
    ATTENDANCE_RECORD_ID, USER_ID, TYPE, REQUESTED_CHECK_IN_AT, REQUESTED_CHECK_OUT_AT, REASON, STATUS
) VALUES (
    #{attendanceRecordId}, #{userId}, #{type}, #{requestedCheckInAt}, #{requestedCheckOutAt}, #{reason}, #{status}
)

mapper.select:
SELECT ID, ATTENDANCE_RECORD_ID, USER_ID, TYPE, REQUESTED_CHECK_IN_AT, REQUESTED_CHECK_OUT_AT, REASON, STATUS, CREATED_AT
FROM ATTENDANCE_REQUESTS
WHERE ID = #{id}

mapper.update:
UPDATE ATTENDANCE_REQUESTS
SET STATUS = #{status}
WHERE ID = #{id}

mapper.select:
SELECT COUNT(*)
FROM ATTENDANCE_REQUESTS
WHERE ATTENDANCE_RECORD_ID = #{attendanceRecordId}
  AND USER_ID = #{userId}
  AND STATUS = 'PENDING'
